// W-Bus protokoll for Webasto Air Top
// Adresser: master=0xF4, heater=0x43

function checksum(bytes) {
    return bytes.reduce((a, b) => a ^ b, 0);
}

function buildPacket(cmd, data) {
    data = data || [];
    var heater = 0x43;
    var master = 0xF4;
    var len    = data.length + 1;
    var packet = [heater, master, len, cmd].concat(data);
    packet.push(checksum(packet));
    return Buffer.from(packet);
}

var command     = msg.payload.command     || 'status';
var temperature = msg.payload.temperature || null;

var packet;
switch (command) {
    case 'start':
        if (temperature !== null) {
            // 0x7D = start med temperatur
            // temp sendes som (°C + 50) * 2 for noen Webasto-modeller
            // Sjekk din modells W-Bus spec om dette ikke virker
            var tempByte = Math.round(temperature * 2) & 0xFF;
            packet = buildPacket(0x7D, [tempByte]);
        } else {
            packet = buildPacket(0x22, []);
        }
        break;
    case 'ventilation':
        // Vifte uten forbrenning
        packet = buildPacket(0x56, []);
        break;
    case 'stop':
        packet = buildPacket(0x10, []);
        break;
    case 'status':
    default:
        packet = buildPacket(0x05, []);
        break;
}

msg._command    = command;
msg._temperature = temperature;
msg._req        = msg.req;
msg._res        = msg.res;
msg.payload     = packet;
return msg;

// Parse W-Bus statussvar fra Webasto
// Format: [addr][master][len][cmd][data...][checksum]

var buf = msg.payload;
if (!Buffer.isBuffer(buf) || buf.length < 4) {
    node.warn('For kort svar: ' + buf.length + ' bytes');
    return null;
}

// Checksum-verifisering
var cs = buf.slice(0, -1).reduce(function(a, b) { return a ^ b; }, 0);
if (cs !== buf[buf.length - 1]) {
    node.warn('W-Bus checksum feil');
    return null;
}

var addr  = buf[0];
var cmd   = buf[3];
var data  = buf.slice(4, -1);

// Status-byte tolkning (kommando 0x05 respons)
var STATE_MAP = {
    0x00: 'off',
    0x01: 'starting',
    0x02: 'running',
    0x04: 'cooling',
    0x08: 'ventilation',
    0x10: 'fault'
};

var statusByte = data.length > 0 ? data[0] : 0;
var state      = STATE_MAP[statusByte] || 'unknown';
var voltage    = data.length > 1 ? data[1] * 0.1 : null;  // V
var temperature = data.length > 2 ? data[2] - 50 : null;   // °C
var faultCode  = (statusByte & 0x10) ? ('0x' + statusByte.toString(16).toUpperCase()) : null;

msg.webastoState = {
    state:       state,
    voltage:     voltage,
    temperature: temperature,
    fault:       statusByte === 0x10,
    faultCode:   faultCode,
    raw:         buf.toString('hex').toUpperCase()
};

node.status({ fill: state==='running'?'green':state==='fault'?'red':'grey', shape:'dot', text: state });
return msg;

var ws = msg.webastoState;
if (!ws) return null;

// Signal K delta-format
msg.payload = {
    updates: [{
        source: { label: 'webasto-wbus', type: 'NMEA2000' },
        timestamp: new Date().toISOString(),
        values: [
            { path: 'environment.heating.0.state',             value: ws.state },
            { path: 'environment.heating.0.operatingVoltage',  value: ws.voltage },
            { path: 'environment.heating.0.currentTemperature', value: ws.temperature !== null ? ws.temperature + 273.15 : null },
            { path: 'environment.heating.0.fault',             value: ws.fault },
            { path: 'environment.heating.0.faultCode',         value: ws.faultCode },
        ].filter(function(v) { return v.value !== null && v.value !== undefined; })
    }]
};
return msg;

msg._req = msg.req;
msg._res = msg.res;
msg.payload = Buffer.from([0x43, 0xF4, 0x01, 0x05, 0x43 ^ 0xF4 ^ 0x01 ^ 0x05]);
return msg;

// Send tilbake nåværende tilstand til BavApp-backenden
var globalCtx = global.get('webastoState') || { state: 'unknown' };
msg.res  = msg._res;
msg.payload = globalCtx;
return msg;

global.set('webastoState', msg.webastoState);

// Send HTTP-svar på den opprinnelige kommando-requesten
if (msg._res) {
    msg.res     = msg._res;
    msg.payload = { ok: true, state: msg.webastoState };
    return msg;
}
return null;
